  timestamp: number;
  audioUrl: string;
}

import { GoogleGenAI, Modality } from "@google/genai";

const API_KEY = process.env.API_KEY || '';

function decode(base64: string) {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
}

async function decodeAudioData(
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
}

/**
 * Encodes AudioBuffer to WAV format for blob creation/download
 */
function audioBufferToWav(buffer: AudioBuffer): Blob {
  const numOfChan = buffer.numberOfChannels;
  const length = buffer.length * numOfChan * 2 + 44;
  const outBuffer = new ArrayBuffer(length);
  const view = new DataView(outBuffer);
  const channels = [];
  let i;
  let sample;
  let offset = 0;
  let pos = 0;

  // write WAVE header
  setUint32(0x46464952); // "RIFF"
  setUint32(length - 8); // file length - 8
  setUint32(0x45564157); // "WAVE"

  setUint32(0x20746d66); // "fmt " chunk
  setUint32(16); // length = 16
  setUint16(1); // PCM (uncompressed)
  setUint16(numOfChan);
  setUint32(buffer.sampleRate);
  setUint32(buffer.sampleRate * 2 * numOfChan); // avg. bytes/sec
  setUint16(numOfChan * 2); // block-align
  setUint16(16); // 16-bit (hardcoded)

  setUint32(0x61746164); // "data" - chunk
  setUint32(length - pos - 4); // chunk length

  // write interleaved data
  for (i = 0; i < buffer.numberOfChannels; i++) {
    channels.push(buffer.getChannelData(i));
  }

  while (pos < length) {
    for (i = 0; i < numOfChan; i++) {
      sample = Math.max(-1, Math.min(1, channels[i][offset])); // clamp
      sample = (0.5 + sample < 0 ? sample * 32768 : sample * 32767) | 0; // scale to 16-bit signed int
      view.setInt16(pos, sample, true); // update pos later
      pos += 2;
    }
    offset++;
  }

  return new Blob([outBuffer], { type: 'audio/wav' });

  function setUint16(data: number) {
    view.setUint16(pos, data, true);
    pos += 2;
  }

  function setUint32(data: number) {
    view.setUint32(pos, data, true);
    pos += 4;
  }
}

export const generateSpeech = async (
  text: string, 
  languageName: string, 
  voiceName: string,
  mood: string = 'neutral'
): Promise<{ audioUrl: string; buffer: AudioBuffer }> => {
  const ai = new GoogleGenAI({ apiKey: API_KEY });

  // Construct a prompt that guides the LLM to speak the content correctly in the target language
  const prompt = `Please speak the following text in ${languageName} with a ${mood} tone: "${text}"`;

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: prompt }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: voiceName },
        },
      },
    },
  });

  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;

  if (!base64Audio) {
    throw new Error('Failed to generate audio content');
  }

  const audioContext = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
  const audioBuffer = await decodeAudioData(
    decode(base64Audio),
    audioContext,
    24000,
    1,
  );

  const wavBlob = audioBufferToWav(audioBuffer);
  const audioUrl = URL.createObjectURL(wavBlob);

  return { audioUrl, buffer: audioBuffer };
};

import React, { useEffect, useRef } from 'react';

interface AudioVisualizerProps {
  audioBuffer: AudioBuffer | null;
  isPlaying: boolean;
  currentTime: number;
}

const AudioVisualizer: React.FC<AudioVisualizerProps> = ({ audioBuffer, isPlaying, currentTime }) => {
  const canvasRef = useRef<HTMLCanvasElement>(null);

  useEffect(() => {
    if (!canvasRef.current || !audioBuffer) return;

    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const data = audioBuffer.getChannelData(0);
    const step = Math.ceil(data.length / canvas.width);
    const amp = canvas.height / 2;

    const draw = () => {
      ctx.clearRect(0, 0, canvas.width, canvas.height);
      ctx.beginPath();
      ctx.moveTo(0, amp);

      for (let i = 0; i < canvas.width; i++) {
        let min = 1.0;
        let max = -1.0;
        for (let j = 0; j < step; j++) {
          const datum = data[i * step + j];
          if (datum < min) min = datum;
          if (datum > max) max = datum;
        }

        const x = i;
        const y = (1 + min) * amp;
        const h = Math.max(1, (max - min) * amp);

        // Highlight played part
        const progress = currentTime / audioBuffer.duration;
        const currentX = canvas.width * progress;

        ctx.fillStyle = x < currentX ? '#3b82f6' : '#cbd5e1';
        ctx.fillRect(x, y, 1, h);
      }
    };

    draw();
  }, [audioBuffer, currentTime]);

  return (
    <div className="w-full bg-slate-50 rounded-xl p-4 border border-slate-200">
      <canvas 
        ref={canvasRef} 
        width={800} 
        height={100} 
        className="w-full h-24 rounded-lg"
      />
    </div>
  );
};

export default AudioVisualizer;

import React, { useState, useRef, useEffect, useCallback } from 'react';
import { LANGUAGES, PREBUILT_VOICES } from './constants';
import { generateSpeech } from './services/geminiService';
import { GenerationHistory, Language, Voice } from './types';
import AudioVisualizer from './components/AudioVisualizer';

const App: React.FC = () => {
  const [text, setText] = useState('Hello! Welcome to Gemini Vox. This is a high-quality AI text to speech generator. টাইপ করুন অথবা আপনার পছন্দমতো ভাষা নির্বাচন করুন।');
  const [selectedLang, setSelectedLang] = useState<Language>(LANGUAGES[0]);
  const [selectedVoice, setSelectedVoice] = useState<Voice>(PREBUILT_VOICES[0]);
  const [mood, setMood] = useState('Friendly');
  const [isGenerating, setIsGenerating] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const [audioUrl, setAudioUrl] = useState<string | null>(null);
  const [audioBuffer, setAudioBuffer] = useState<AudioBuffer | null>(null);
  const [history, setHistory] = useState<GenerationHistory[]>([]);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);

  const audioRef = useRef<HTMLAudioElement | null>(null);

  const handleGenerate = async () => {
    if (!text.trim()) return;

    setIsGenerating(true);
    setError(null);

    try {
      const result = await generateSpeech(text, selectedLang.name, selectedVoice.id, mood);
      setAudioUrl(result.audioUrl);
      setAudioBuffer(result.buffer);

      const newHistory: GenerationHistory = {
        id: Date.now().toString(),
        text,
        language: selectedLang.name,
        voice: selectedVoice.id,
        timestamp: Date.now(),
        audioUrl: result.audioUrl
      };

      setHistory(prev => [newHistory, ...prev].slice(0, 10));
    } catch (err: any) {
      console.error(err);
      setError(err.message || 'An error occurred while generating audio.');
    } finally {
      setIsGenerating(false);
    }
  };

  const togglePlay = () => {
    if (!audioRef.current) return;
    if (isPlaying) {
      audioRef.current.pause();
    } else {
      audioRef.current.play();
    }
  };

  const onTimeUpdate = () => {
    if (audioRef.current) {
      setCurrentTime(audioRef.current.currentTime);
    }
  };

  const handleDownload = () => {
    if (!audioUrl) return;
    const a = document.createElement('a');
    a.href = audioUrl;
    a.download = `gemini-vox-${Date.now()}.wav`;
    a.click();
  };

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 pb-20">
      {/* Navbar */}
      <nav className="sticky top-0 z-50 glass-morphism border-b border-slate-200 px-6 py-4">
        <div className="max-w-6xl mx-auto flex items-center justify-between">
          <div className="flex items-center space-x-2">
            <div className="bg-blue-600 p-2 rounded-lg">
              <i className="fas fa-wave-square text-white text-xl"></i>
            </div>
            <h1 className="text-2xl font-bold tracking-tight text-slate-800">
              Gemini <span className="text-blue-600">Vox</span>
            </h1>
          </div>
          <div className="hidden md:flex space-x-6 text-sm font-medium text-slate-600">
            <a href="#" className="hover:text-blue-600 transition">Dashboard</a>
            <a href="#" className="hover:text-blue-600 transition">API Docs</a>
            <a href="#" className="hover:text-blue-600 transition">Pricing</a>
          </div>
          <button className="bg-slate-900 text-white px-4 py-2 rounded-full text-sm font-semibold hover:bg-slate-800 transition shadow-sm">
            Upgrade Pro
          </button>
        </div>
      </nav>

      <main className="max-w-6xl mx-auto mt-8 px-6 grid grid-cols-1 lg:grid-cols-3 gap-8">

        {/* Left Column: Input & Controls */}
        <div className="lg:col-span-2 space-y-6">
          <div className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100">
            <div className="flex items-center justify-between mb-4">
              <label className="text-sm font-semibold text-slate-500 uppercase tracking-wider">Input Text</label>
              <span className="text-xs text-slate-400">{text.length} characters</span>
            </div>
            <textarea
              className="w-full h-64 p-4 text-lg bg-slate-50 rounded-2xl border border-slate-200 focus:ring-4 focus:ring-blue-100 focus:border-blue-500 outline-none transition resize-none placeholder-slate-300"
              placeholder="Enter text to convert to high-quality AI speech..."
              value={text}
              onChange={(e) => setText(e.target.value)}
            />

            <div className="mt-6 flex flex-wrap gap-4">
              <button 
                onClick={handleGenerate}
                disabled={isGenerating || !text.trim()}
                className={`flex-1 min-w-[200px] flex items-center justify-center space-x-2 py-4 rounded-2xl font-bold text-lg transition shadow-lg ${
                  isGenerating 
                  ? 'bg-slate-200 text-slate-400 cursor-not-allowed' 
                  : 'bg-blue-600 text-white hover:bg-blue-700 active:scale-95'
                }`}
              >
                {isGenerating ? (
                  <>
                    <i className="fas fa-spinner fa-spin"></i>
                    <span>Generating...</span>
                  </>
                ) : (
                  <>
                    <i className="fas fa-wand-magic-sparkles"></i>
                    <span>Generate Audio</span>
                  </>
                )}
              </button>

              <button 
                onClick={() => setText('')}
                className="px-6 py-4 bg-slate-100 text-slate-600 rounded-2xl hover:bg-slate-200 transition font-medium"
              >
