              </button>
            </div>

            {error && (
              <div className="mt-4 p-4 bg-red-50 text-red-600 rounded-xl border border-red-100 flex items-center space-x-2">
                <i className="fas fa-circle-exclamation"></i>
                <span className="text-sm font-medium">{error}</span>
              </div>
            )}
          </div>

          {/* Player Section */}
          {(audioUrl || audioBuffer) && (
            <div className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100 animate-in fade-in slide-in-from-bottom-4 duration-500">
              <div className="flex items-center justify-between mb-6">
