                <div className="flex space-x-2">
                  <button 
                    onClick={handleDownload}
                    className="p-2 text-slate-500 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition"
                    title="Download"
                  >
                    <i className="fas fa-download"></i>
                  </button>
                </div>
              </div>

