                >
                  <i className={`fas ${isPlaying ? 'fa-pause' : 'fa-play'}`}></i>
                </button>

                <div className="flex-1">
                  <div className="text-sm font-medium text-slate-600 mb-1">
                    {currentTime.toFixed(1)}s / {audioBuffer?.duration.toFixed(1)}s
                  </div>
                  <div className="h-1.5 w-full bg-slate-100 rounded-full overflow-hidden">
                    <div 
                      className="h-full bg-blue-600 transition-all duration-100" 
                      style={{ width: `${(currentTime / (audioBuffer?.duration || 1)) * 100}%` }}
                    />
                  </div>
                </div>
              </div>

              <audio 
                ref={audioRef} 
                src={audioUrl || ''} 
                onPlay={() => setIsPlaying(true)}
                onPause={() => setIsPlaying(false)}
                onTimeUpdate={onTimeUpdate}
                onEnded={() => setIsPlaying(false)}
                className="hidden"
              />
            </div>
          )}
        </div>

        {/* Right Column: Settings */}
        <div className="space-y-6">
          {/* Language Selector */}
          <div className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100">
            <h3 className="text-sm font-semibold text-slate-500 uppercase tracking-wider mb-4">Settings</h3>

            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-2">Language</label>
                <div className="relative">
                  <select 
                    value={selectedLang.code}
                    onChange={(e) => {
                      const lang = LANGUAGES.find(l => l.code === e.target.value);
                      if (lang) setSelectedLang(lang);
                    }}
                    className="w-full appearance-none bg-slate-50 border border-slate-200 rounded-xl px-4 py-3 outline-none focus:border-blue-500 cursor-pointer"
                  >
                    {LANGUAGES.map(lang => (
                      <option key={lang.code} value={lang.code}>
                        {lang.name} ({lang.nativeName})
                      </option>
                    ))}
                  </select>
                  <div className="absolute right-4 top-1/2 -translate-y-1/2 pointer-events-none text-slate-400">
                    <i className="fas fa-chevron-down text-xs"></i>
                  </div>
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-2">Voice Identity</label>
                <div className="grid grid-cols-2 gap-2">
                  {PREBUILT_VOICES.map(voice => (
                    <button
                      key={voice.id}
                      onClick={() => setSelectedVoice(voice)}
                      className={`p-3 rounded-xl border text-left transition ${
                        selectedVoice.id === voice.id 
                        ? 'bg-blue-50 border-blue-500 ring-1 ring-blue-500' 
                        : 'bg-slate-50 border-slate-200 hover:border-slate-300'
                      }`}
                    >
                      <div className="text-sm font-bold truncate">{voice.name}</div>
                      <div className="text-[10px] text-slate-500 truncate">{voice.description}</div>
                    </button>
                  ))}
                </div>
              </div>

              <div>
                <label className="block text-sm font-medium text-slate-700 mb-2">Tone/Mood</label>
                <div className="flex flex-wrap gap-2">
                  {['Friendly', 'Serious', 'Whisper', 'Excited', 'Narrator'].map(m => (
                    <button
                      key={m}
                      onClick={() => setMood(m)}
                      className={`px-3 py-1.5 rounded-full text-xs font-semibold transition ${
                        mood === m 
                        ? 'bg-slate-900 text-white' 
                        : 'bg-slate-100 text-slate-600 hover:bg-slate-200'
                      }`}
                    >
                      {m}
                    </button>
                  ))}
                </div>
              </div>
            </div>
          </div>

          {/* History */}
          {history.length > 0 && (
            <div className="bg-white rounded-3xl p-6 shadow-sm border border-slate-100">
              <h3 className="text-sm font-semibold text-slate-500 uppercase tracking-wider mb-4">Recent</h3>
              <div className="space-y-3">
                {history.map(item => (
                  <div key={item.id} className="group p-3 bg-slate-50 rounded-xl border border-slate-200 hover:bg-slate-100 transition cursor-pointer" onClick={() => setAudioUrl(item.audioUrl)}>
                    <div className="flex items-center justify-between mb-1">
                      <span className="text-[10px] font-bold text-blue-600 bg-blue-50 px-2 py-0.5 rounded uppercase">{item.language}</span>
                      <span className="text-[10px] text-slate-400">{new Date(item.timestamp).toLocaleTimeString()}</span>
                    </div>
                    <p className="text-xs text-slate-600 line-clamp-1 italic">"{item.text}"</p>
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      </main>

      {/* Footer Info */}
      <footer className="max-w-6xl mx-auto mt-12 px-6 text-center text-slate-400 text-xs">
        <p>© 2024 Gemini Vox AI. Powered by Google Gemini 2.5 Flash. Supports 20+ Expressive Voices & 70+ Languages.</p>
      </footer>
    </div>
  );
};

